def largest_divisor(n: int) -> int:
    """ For a given number n, find the largest number that divides n evenly, smaller than n
    >>> largest_divisor(15)
    5
    """
    # Start searching from n-1 downwards to find the largest divisor
    for i in range(n - 1, 0, -1):
        if n % i == 0:
            return i
    return 1

def flip_case(string: str) -> str:
    """ For a given string, flip lowercase characters to uppercase and uppercase to lowercase.
    >>> flip_case('Hello')
    'hELLO'
    """
    result = []
    for char in string:
        if char.islower():
            result.append(char.upper())
        elif char.isupper():
            result.append(char.lower())
        else:
            result.append(char)
    return "".join(result)

def prime_fib(n: int):
    """
    prime_fib returns n-th number that is a Fibonacci number and it's also prime.
    """
    def is_prime(num: int) -> bool:
        if num < 2:
            return False
        if num == 2 or num == 3:
            return True
        if num % 2 == 0 or num % 3 == 0:
            return False
        i = 5
        while i * i <= num:
            if num % i == 0 or num % (i + 2) == 0:
                return False
            i += 6
        return True

    count = 0
    a, b = 0, 1

    while count < n:
        # Generate next Fibonacci number
        a, b = b, a + b

        # Check if the current Fibonacci number is prime
        # Note: Fibonacci sequence starts 0, 1, 1, 2, 3, 5...
        # We start checking from the first 'b' which is 1, then 1, 2, 3...
        # is_prime handles values < 2 correctly.
        if is_prime(b):
            count += 1
            if count == n:
                return b

def triples_sum_to_zero(l: list):
