def get_row(lst, x):
    """
    Finds all occurrences of x in a nested list and returns coordinates (row, col).
    Coordinates are sorted by row ascending, then by column descending.
    """
    coords = []
    for r_idx, row in enumerate(lst):
        for c_idx, val in enumerate(row):
            if val == x:
                coords.append((r_idx, c_idx))

    # Sort by row ascending (x[0]), then by column descending (-x[1])
    coords.sort(key=lambda coord: (coord[0], -coord[1]))

    return coords

