def intersection(interval1, interval2):
    """
    Determines whether the length of the intersection of two closed intervals is a prime number.
    """
    # Calculate the bounds of the intersection
    start_max = max(interval1[0], interval2[0])
    end_min = min(interval1[1], interval2[1])

    # Calculate length of intersection
    # If start_max > end_min, there is no intersection
    if start_max >= end_min:
        length = 0
    else:
        length = end_min - start_max

    # Primality check
    if length < 2:
        return "NO"

    if length == 2:
        return "YES"

    if length % 2 == 0:
        return "NO"

    for i in range(3, int(length**0.5) + 1, 2):
        if length % i == 0:
            return "NO"

    return "YES"

def prod_signs(arr):
    """
    Returns the sum of magnitudes of integers multiplied by the product of all signs.
    Returns None for empty arr.
    """
    if not arr:
        return None

    sum_magnitudes = 0
    product_signs = 1

    for x in arr:
        sum_magnitudes += abs(x)

        if x > 0:
            product_signs *= 1
        elif x < 0:
            product_signs *= -1
        else:
            # If any element is 0, the product of signs is 0
            product_signs = 0
            break

    return sum_magnitudes * product_signs

def minPath(grid, k):
    n = len(grid)

    def get_neighbors(r, c):
        res = []
        for dr, dc in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
            nr, nc = r + dr, c + dc
            if 0 <= nr < n and 0 <= nc < n:
                res.append((nr, nc))
        return res

    def find_cell_by_value(target):
        for r in range(n):
            for c in range(n):
                if grid[r][c] == target:
                    return r, c
        return -1, -1

    # The grid contains values 1 to N*N exactly once.
    # The smallest possible value in the grid is 1.
    # To minimize lexicographically, we want the smallest possible start.
    # However, we must consider that the path must be valid.
    # Since we can oscillate, the best path of length k > 1 will start at some cell 'u'
    # and move to its smallest neighbor 'v', then back to 'u', etc.
    # We need to find the cell 'u' such that the pair (grid[u], grid[v]) is minimal.

    best_pair = (float('inf'), float('inf'))

    for r in range(n):
        for c in range(n):
            val = grid[r][c]
            neighbors = get_neighbors(r, c)
            min_neighbor_val = min(grid[nr][nc] for nr, nc in neighbors)
            if (val, min_neighbor_val) < best_pair:
                best_pair = (val, min_neighbor_val)

    u_val, v_val = best_pair
    res = []
    for i in range(k):
        res.append(u_val if i % 2 == 0 else v_val)
    return res

def tri(n):
    if n < 0:
        return []

    res = [0] * (n + 1)

    # Base cases
    if n >= 0:
        res[0] = 1
    if n >= 1:
        res[1] = 3

    # Fill even indices first because odd indices depend on (i + 1)
    # which is always even if i is odd.
    for i in range(2, n + 1):
        if i % 2 == 0:
            res[i] = 1 + (i // 2)

    # Fill odd indices
    for i in range(2, n + 1):
        if i % 2 != 0:
            # tri(n) = tri(n-1) + tri(n-2) + tri(n+1)
            res[i] = res[i-1] + res[i-2] + (1 + (i + 1) // 2)

    return res

