def fix_spaces(text):
    """
    Given a string text, replace all spaces in it with underscores, 
    and if a string has more than 2 consecutive spaces, 
    then replace all consecutive spaces with - 
    """
    if not text:
        return ""

    result = []
    i = 0
    n = len(text)

    while i < n:
        if text[i] == ' ':
            start = i
            while i < n and text[i] == ' ':
                i += 1
            count = i - start
            result.append('-' if count > 2 else '_' * count)
        else:
            result.append(text[i])
            i += 1
    return "".join(result)

def words_in_sentence(sentence):
    """
    Returns a string containing words from the original sentence whose lengths are prime numbers.
    """
    def is_prime(n):
        if n < 2:
            return False
        for i in range(2, int(n**0.5) + 1):
            if n % i == 0:
                return False
        return True

    # Tokenization: Split by single space
    words = sentence.split(' ')

    # Filtering: Keep words with prime lengths
    prime_length_words = []
    for word in words:
        if is_prime(len(word)):
            prime_length_words.append(word)

    # Reconstruction: Join with single space
    return " ".join(prime_length_words)

