        if not s:
            return 0

        if s[0] == '-':
            # For negative integers, the first digit is treated as negative,
            # and all subsequent digits are treated as positive.
            # Example: -123 -> -1 + 2 + 3 = 4
            first_digit = -int(s[1])
            remaining_digits = sum(int(d) for d in s[2:])
            return first_digit + remaining_digits
        else:
            # For positive integers, all digits are summed.
            return sum(int(d) for d in s)

    return sorted(nums, key=calculate_digit_sum)

def special_filter(numbers):
    count = 0
    odd_digits = {'1', '3', '5', '7', '9'}

    for num in numbers:
        if num > 10:
            # Convert absolute value to string to extract digits
            s_num = str(abs(num))
            first_digit = s_num[0]
            last_digit = s_num[-1]

            if first_digit in odd_digits and last_digit in odd_digits:
                count += 1
    return count

def x_or_y(n, x, y):
    """A simple program which should return the value of x if n is 
    a prime number and should return the value of y otherwise.

    Examples:
    for x_or_y(7, 34, 12) == 34
    for x_or_y(15, 8, 5) == 5

    """
    if n < 2:
        return y
    if n == 2:
        return x
    if n % 2 == 0:
        return y
    for i in range(3, int(n**0.5) + 1, 2):
        if n % i == 0:
            return y
    return x

def double_the_difference(lst):
    '''
    Given a list of numbers, return the sum of squares of the numbers
    in the list that are odd. Ignore numbers that are negative or not integers.
    '''
    res = 0
    for x in lst:
        if isinstance(x, int) and x >= 0:
            if x % 2 != 0:
                res += x * x
    return res

def even_odd_count(num):
    """Given an integer. return a tuple that has the number of even and odd digits respectively.
     Example:
        even_odd_count(-12) ==> (1, 1)
        even_odd_count(123) ==> (1, 2)
    """
    even_count = 0
    odd_count = 0
    for digit_char in str(abs(num)):
        digit = int(digit_char)
        if digit % 2 == 0:
            even_count += 1
        else:
            odd_count += 1
    return (even_count, odd_count)

def solve(s):
    has_letter = any(c.isalpha() for c in s)

    if has_letter:
        result = []
        for char in s:
            result.append(char.swapcase())
        return "".join(result)
    else:
        return s[::-1]

def prime_length(string):
    """Write a function that takes a string and returns True if the string
    length is a prime number or False otherwise
    """
    n = len(string)

    if n < 2:
        return False
    if n == 2:
        return True
    if n % 2 == 0:
        return False

    i = 3
    while i * i <= n:
        if n % i == 0:
            return False
        i += 2
    return True

def anti_shuffle(s):
    """
    Write a function that takes a string and returns an ordered version of it.
    Ordered version of string, is a string where all words (separated by space)
    are replaced by a new word where all the characters arranged in
    ascending order based on ascii value.
    Note: You should keep the order of words and blank spaces in the sentence.
    """
    res = []
    word_buffer = []

    for char in s:
        if char == ' ':
            if word_buffer:
                res.append("".join(sorted(word_buffer)))
                word_buffer = []
            res.append(char)
        else:
            word_buffer.append(char)

    if word_buffer:
        res.append("".join(sorted(word_buffer)))

    return "".join(res)

def sum_squares(lst):
    result_sum = 0
    for i in range(len(lst)):
        val = lst[i]
        if i % 3 == 0:
            # Rule: If index is multiple of 3, square it.
            # Note: Index 0 is a multiple of 3.
            result_sum += val ** 2
        elif i % 4 == 0:
            # Rule: If index is multiple of 4 and NOT 3, cube it.
            result_sum += val ** 3
        else:
            # Rule: Otherwise, no change.
            result_sum += val
    return result_sum
